const results = [];
const items = $input.all();
let channels = [];
try {
  channels = $('Get Active Slack Channels').all();
} catch (e) {
  console.log('[Parse Slack] Could not read from Get Active Slack Channels node:', e.message);
}

for (const item of items) {
  const pairedIndex = (item.pairedItem && typeof item.pairedItem.index === 'number') ? item.pairedItem.index : 0;
  const channel = (channels[pairedIndex] && channels[pairedIndex].json) ? channels[pairedIndex].json : { channel_db_id: 1, channel_id: 'C5GQ29DBM' };
  const channel_db_id = channel.channel_db_id;
  const channel_id = channel.channel_id;

  const messages = item.json.messages || [];
  for (const msg of messages) {
    if (msg.subtype && msg.subtype !== 'bot_message') continue;

    const messageId = `${channel_id}_${msg.ts}`;
    const created_at = new Date(parseFloat(msg.ts) * 1000).toISOString();
    const cleanTs = msg.ts.replace('.', '');
    const url = `https://slack.com/archives/${channel_id}/p${cleanTs}`;

    results.push({
      id: messageId,
      channel_db_id: channel_db_id,
      author: msg.user || msg.bot_id || 'unknown',
      content: msg.text || '',
      url: url,
      created_at: created_at,
      processed: 0
    });
  }
}

return results;
